function renounceOwnership() public virtual onlyOwner {
    emit OwnershipTransferred(_owner, address(0));
    _owner = address(0);
}

function ownerOf(uint256 tokenId) external view returns (address owner) {
    owner = _owners[tokenId];
    if (owner == address(0)) {
        revert InvalidTokenError(tokenId);
    }
}

function setPublicationFee(uint256 _publicationFee) external onlyOwner {
  publicationFeeInWei = _publicationFee;
  emit ChangedPublicationFee(publicationFeeInWei);
}

interface IERC721CollectionV2 {
    function creator() external view returns (address);
    function decodeTokenId(uint256 _tokenId) external view returns (uint256, uint256);
    function items(uint256 _itemId) external view returns (string memory, uint256, uint256, uint256, address, string memory, string memory);
}

function _checkRole(bytes32 role, address account) internal view virtual {
    if (!_hasRole[role][account]) {
        revert PermissionsUnauthorizedAccount(account, role);
    }
}

if (assets[name].enabled) {
    return false;
} else {
    assets[name] = Asset(true, 0);
    return true;
}

function deployUUPSProxy(address impl, bytes memory initializerData) internal returns (address) {
    return address(new ERC1967Proxy(impl, initializerData));
}

function upgradeProxy(address proxy, address newImpl, bytes memory data) internal {
    Core.upgradeProxyTo(proxy, newImpl, data);
}

function upgradeProxy(address proxy, string memory contractName, bytes memory data, Options memory opts) internal {
    address newImpl = prepareUpgrade(contractName, opts);
    upgradeProxyTo(proxy, newImpl, data);
}

event PBTChipRemapping(
    uint256 indexed tokenId, address indexed oldChipAddress, address indexed newChipAddress
);

struct Memo {
    uint256 numCoffees;
    string message;
    uint256 time;
    address userAddress;
}

struct Permit2SignatureTransferData {
    ISignatureTransfer.PermitTransferFrom permit;
    ISignatureTransfer.SignatureTransferDetails transferDetails;
    bytes signature;
}

struct EIP712Domain {
    string name;
    string version;
    address verifyingContract;
    bytes32 salt;
}

event BridgehubDepositBaseTokenInitiated(
    uint256 indexed chainId,
    address indexed from,
    bytes32 assetId,
    uint256 amount
);

if (permissions.intersection(requirement).isEmpty()) {
    revert MissingPermissions(msg.sender, permissions, requirement);
}

struct ApprovalProcessResponse {
    string approvalProcessId;
    address via;
    string viaType;
}

require(
  isNotAccount(msg.sender) && isNotAuthorizedSigner(msg.sender),
  "Account already exists or address is an authorized signer for another account"
);

function deployUUPSProxy(string memory contractName, bytes memory initializerData) internal returns (address) {
    Options memory opts;
    return deployUUPSProxy(contractName, initializerData, opts);
}

function deployContract(
    string memory contractName,
    DefenderOptions memory defenderOpts
) internal returns (address) {
    return deployContract(contractName, "", defenderOpts);
}

struct AccessControlEnumerableStorage {
    mapping(bytes32 role => EnumerableSet.AddressSet) _roleMembers;
}

require(
  signerAuthorizations[account][role][msg.sender].started == true,
  "Signer authorization not started"
);

struct Lookup {
    address target; // contract to call
    bytes call; // initial calldata
    bytes data; // response or error
    uint256 flags; // see: FLAG_*
}

uint256 transcoderRewardStakeFees = PreciseMathUtils.percOf(
    delegatorsFees,
    activeCumulativeRewards,
    totalStake
);

require(
  isNotAuthorizedSignerForAnotherAccount(msg.sender, signer),
  "Not a signer for this account"
);

require(
  isNotAccount(signer) && isNotAuthorizedSignerForAnotherAccount(msg.sender, signer),
  "Cannot re-authorize address signer"
);

require(
  isNotAccount(msg.sender) && isNotAuthorizedSignerForAnotherAccount(account, msg.sender),
  "Cannot re-authorize address signer"
);

function _validateHookAddress(BaseHook hook) internal pure {
    Hooks.validateHookPermissions(hook, getHookPermissions());
}
